// Deduplicate within NEW_WORDS (by lowercase word)
const seenWords = new Set();
const DEDUPED_WORDS = NEW_WORDS.filter(w => {
  const key = w.word.toLowerCase();
  if (seenWords.has(key)) {
    console.log(`  ⚠️  Removing internal duplicate: "${w.word}"`);
    return false;
  }
  seenWords.add(key);
  return true;
});
console.log(`  After internal dedup: ${DEDUPED_WORDS.length} unique words`);

// ============================================================
// Build filename and path for the vocabulary JSON
// ============================================================
const VOCAB_FILE = path.join(__dirname, '..', 'data', 'vocabulary.json');

// ============================================================
// Batch enrich each word via the Free Dictionary API
// Returns { phonetic, audioUrl } or empty values on failure
// ============================================================
function fetchDictionary(word) {
  return new Promise((resolve) => {
    const clean = word.trim().toLowerCase().replace(/[^a-z -]/g, '').replace(/\s+/g, ' ');
    // Skip multi-word terms — Free Dictionary API only supports single words
    const isSingleWord = /^[a-z-]+$/.test(clean);
    if (!isSingleWord) {
      resolve({ phonetic: '', audioUrl: '' });
      return;
    }
    const apiUrl = `https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(clean)}`;
    const req = https.get(apiUrl, { headers: { 'Accept': 'application/json' }, timeout: 8000 }, (res) => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        if (res.statusCode === 404) { resolve({ phonetic: '', audioUrl: '' }); return; }
        try {
          const data = JSON.parse(body);
          if (!Array.isArray(data) || data.length === 0) { resolve({ phonetic: '', audioUrl: '' }); return; }
          const entry = data[0];
          const phonetic = entry.phonetic || entry.phonetics?.find(p => p.text)?.text || '';
          const audioUrl = entry.phonetics?.find(p => p.audio)?.audio || '';
          resolve({ phonetic, audioUrl });
        } catch (_) { resolve({ phonetic: '', audioUrl: '' }); }
      });
    });
    req.on('error', () => resolve({ phonetic: '', audioUrl: '' }));
    req.on('timeout', () => { req.destroy(); resolve({ phonetic: '', audioUrl: '' }); });
  });
}

// ============================================================
// Main: enrich words in batches with concurrency limit
// ============================================================
async function enrichAll(words) {
  const CONCURRENCY = 5; // parallel requests to avoid rate-limiting
  const enriched = [];
  console.log(`\n  Enriching ${words.length} words via Free Dictionary API...\n`);
  console.log(`  Concurrency: ${CONCURRENCY} | Estimated time: ~${Math.ceil(words.length / CONCURRENCY * 1.5)} seconds\n`);

  for (let i = 0; i < words.length; i += CONCURRENCY) {
    const batch = words.slice(i, i + CONCURRENCY);
    const results = await Promise.all(batch.map(async (item) => {
      const { phonetic, audioUrl } = await fetchDictionary(item.word);
      item.phonetic = phonetic;
      item.audioUrl = audioUrl;
      return item;
    }));
    enriched.push(...results);

    const done = Math.min(i + CONCURRENCY, words.length);
    const withAudio = enriched.filter(w => w.audioUrl).length;
    const withPhonetic = enriched.filter(w => w.phonetic).length;
    process.stdout.write(`\r  Progress: ${done}/${words.length} | audio: ${withAudio} | phonetic: ${withPhonetic}`);
  }

  console.log('\n');
  return enriched;
}

// ============================================================
// Print a word summary with missing fields flagged
// ============================================================
function summarise(words) {
  const withAudio = words.filter(w => w.audioUrl).length;
  const withPhonetic = words.filter(w => w.phonetic).length;
  const themes = [...new Set(words.map(w => w.theme))];
  const byTheme = {};
  themes.forEach(t => { byTheme[t] = words.filter(w => w.theme === t).length; });
  console.log('\n  ── Summary ──');
  console.log(`  Total words:         ${words.length}`);
  console.log(`  With audio URL:      ${withAudio}/${words.length}`);
  console.log(`  With phonetic:       ${withPhonetic}/${words.length}`);
  console.log(`  Unique themes:       ${themes.length}`);
  console.log(`  Theme distribution:`);
  Object.entries(byTheme).sort((a, b) => b[1] - a[1]).forEach(([theme, count]) => {
    console.log(`    ${theme}: ${count}`);
  });
}

