// MAIN
// ============================================================
(async () => {
  console.log('\n  ═══════════════════════════════════════');
  console.log('    IELTS Vocabulary Generator');
  console.log('  ═══════════════════════════════════════');
  console.log(`\n  New words to generate: ${DEDUPED_WORDS.length}`);

  // Step 1: Read existing vocabulary
  let existing = [];
  try {
    existing = JSON.parse(fs.readFileSync(VOCAB_FILE, 'utf-8'));
    console.log(`  Existing vocabulary entries: ${existing.length}`);
  } catch (err) {
    console.log('  No existing vocabulary.json found. Starting fresh.');
  }

  // Step 2: Enrich new words with API data
  const enrichedNewWords = await enrichAll(DEDUPED_WORDS);

  // Step 3: Merge — assign sequential IDs starting from max(existing) + 1
  const maxId = existing.length > 0 ? Math.max(...existing.map(w => w.id)) : 0;
  const newWithIds = enrichedNewWords.map((w, i) => ({
    id: maxId + i + 1,
    word: w.word,
    pos: w.pos,
    chinese: w.chinese,
    synonyms: w.synonyms,
    definition: w.definition,
    example: w.example,
    theme: w.theme,
    difficulty: w.difficulty,
    phonetic: w.phonetic || '',
    audioUrl: w.audioUrl || '',
  }));

  // Step 4: Validate — check for missing required fields
  const required = ['id', 'word', 'pos', 'chinese', 'synonyms', 'definition', 'example', 'theme', 'difficulty'];
  const invalid = newWithIds.filter(w => required.some(f => !w[f] || (Array.isArray(w[f]) && w[f].length === 0)));
  if (invalid.length > 0) {
    console.log(`\n  ⚠️  ${invalid.length} entries with missing required fields:`);
    invalid.forEach(w => {
      const missing = required.filter(f => !w[f] || (Array.isArray(w[f]) && w[f].length === 0));
      console.log(`    - ${w.word} (id:${w.id}) missing: ${missing.join(', ')}`);
    });
  }

  // Step 5: Dedup — remove any duplicate words vs existing
  const existingWords = new Set(existing.map(w => w.word.toLowerCase()));
  const deduped = newWithIds.filter(w => !existingWords.has(w.word.toLowerCase()));
  if (deduped.length < newWithIds.length) {
    console.log(`\n  ⚠️  Removed ${newWithIds.length - deduped.length} duplicate words already in vocabulary.json`);
  }

  // Step 6: Combine and write
  const final = [...existing, ...deduped];
  console.log(`\n  Writing ${final.length} total entries to vocabulary.json...`);
  fs.writeFileSync(VOCAB_FILE, JSON.stringify(final, null, 2), 'utf-8');
  console.log(`  ✅ Successfully wrote ${final.length} entries.`);
  console.log(`     Original: ${existing.length} | New: ${deduped.length}`);

  summarise(final);

  // Step 7: Verify no alcohol/pub content (use word-boundary regex for short terms)
  const bannedPatterns = [
    /\bpub\b/, /\bbars\b/, /\bbar\b/, /\balcohol\b/, /\bbeer\b/, /\bwine\b/,
    /\bliquor\b/, /\bdrinking\b/, /\bdrunken\b/, /\bcocktail\b/, /\bbrewery\b/,
    /\btavern\b/, /\bnightclub\b/, /\bbartender\b/, /\btipsy\b/, /\bhangover\b/,
    /\bvodka\b/, /\bwhisky\b/, /\bwhiskey\b/, /\bchampagne\b/, /\balcoholic\b/,
    /\bpubbing\b/, /\bdrunk\b/
  ];
  const violations = final.filter(w => {
    const text = (w.example + w.definition + ' ' + w.word).toLowerCase();
    return bannedPatterns.some(pattern => pattern.test(text));
  });
  if (violations.length > 0) {
    console.log(`\n  ❌ CONTENT VIOLATIONS FOUND (alcohol/pub references):`);
    violations.forEach(v => console.log(`    - ${v.word}: ${v.example}`));
    console.log('  Please remove these entries before deploying.');
  } else {
    console.log(`\n  ✅ No alcohol/pub content violations detected.`);
  }

  console.log('\n  Done.\n');
})();
